const allGMB = $('Has 1-Star Reviews?').all()
const result = []

for (const gmb of allGMB) {
  const reviews = gmb.json.reviews || []
  const oneStar = gmb.json.reviewsDistribution?.oneStar || 0
  let reviewWithImage = ''

  for (let i = 0; i < Math.min(reviews.length, 10); i++) {
    const rev = reviews[i]
    if (rev && Array.isArray(rev.reviewImageUrls) && rev.reviewImageUrls.length > 0) {
      reviewWithImage = rev.reviewUrl || ''
      break
    }
  }

  result.push({
    json: {
      'Business Name': gmb.json.title || '',
      'GMB URL': gmb.json.url || '',
      'City[Location]': gmb.json.address || '',
      'Phone Number': gmb.json.phone ? `(${String(gmb.json.phone)})` : '',
      'Alternative Number': gmb.json.phoneUnformatted || '',
      'Business Email': (gmb.json.emails && gmb.json.emails.length > 0) ? gmb.json.emails[0] : '',
      'Negative review URLs': reviews[0]?.reviewUrl || '',
      'Negative review URL With Image': reviewWithImage,
      'One Star Review Count': oneStar
    }
  })
}

return result
